@using sv_8edcc67696ce46439bacffe763cfca72.Services
@inject WarehouseState Warehouse
@implements IDisposable
@rendermode InteractiveServer

<select class="form-select form-select-sm" value="@Warehouse.CurrentWarehouseId"
        @onchange="OnWarehouseChanged" style="width: auto;">
    @foreach (var wh in WarehouseState.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        Warehouse.SetWarehouse(e.Value?.ToString() ?? string.Empty);
    }

    protected override void OnInitialized()
    {
        Warehouse.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Warehouse.OnChange -= StateHasChanged;
    }
}

@using sv_8edcc67696ce46439bacffe763cfca72.Services
@inject InventoryAlertService Alerts
@implements IDisposable
@rendermode InteractiveServer

@if (Alerts.CurrentAlertCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@Alerts.CurrentAlertCount</span>
}

@code {
    private Action? _handler;

